        await recordAttempt(username, ipAddress, false);
        throw new AppError(401, "invalid_credentials", "Invalid credentials");
      }

      const matches = await bcrypt.compare(password, user.password_hash);
      if (!matches) {
        await recordAttempt(username, ipAddress, false);
        throw new AppError(401, "invalid_credentials", "Invalid credentials");
