           WHERE id = ?`,
          [
            cryptoService.hashForComparison(rawToken),
            encryptedSecret.cipherText,
            encryptedSecret.keyId,
            Number(row.id)
          ]
        );
      }
    },

    warmLockSession,
    assertSessionActive,
    touchSession
  };
