174	  let brightnessTotal = 0;
175	  let brightnessCount = 0;
176	
177	  for (let y = 0; y < height; y += sampleStep) {
178	    for (let x = 0; x < width; x += sampleStep) {
179	      brightnessTotal += Jimp.intToRGBA(grayscale.getPixelColor(x, y)).r;
180	      brightnessCount += 1;
181	    }
182	  }
183	
184	  const meanBrightness = brightnessTotal / brightnessCount;
185	  const darkThreshold = clamp(meanBrightness - 20, 24, 210);
186	  const horizontalMargin = width * 0.08;
187	  const verticalMargin = height * 0.08;
188	
189	  let totalWeight = 0;
190	  let weightedX = 0;
191	  let weightedY = 0;
192	  let varianceX = 0;
193	  let varianceY = 0;
194	
195	  for (let y = Math.floor(verticalMargin); y < Math.ceil(height - verticalMargin); y += sampleStep) {
196	    for (let x = Math.floor(horizontalMargin); x < Math.ceil(width - horizontalMargin); x += sampleStep) {
197	      const brightness = Jimp.intToRGBA(grayscale.getPixelColor(x, y)).r;
198	      const weight = Math.max(0, darkThreshold - brightness);
199	      if (weight <= 0) {
200	        continue;
201	      }
202	
203	      totalWeight += weight;
204	      weightedX += x * weight;
205	      weightedY += y * weight;
206	    }
207	  }
208	
209	  if (totalWeight <= 200) {
210	    throw new AppError(400, "face_box_invalid", "A trusted face region could not be derived from the image");
211	  }
212	
213	  const centroidX = weightedX / totalWeight;
214	  const centroidY = weightedY / totalWeight;
215	
216	  for (let y = Math.floor(verticalMargin); y < Math.ceil(height - verticalMargin); y += sampleStep) {
217	    for (let x = Math.floor(horizontalMargin); x < Math.ceil(width - horizontalMargin); x += sampleStep) {
218	      const brightness = Jimp.intToRGBA(grayscale.getPixelColor(x, y)).r;
219	      const weight = Math.max(0, darkThreshold - brightness);
220	      if (weight <= 0) {
221	        continue;
222	      }
223	
224	      varianceX += (x - centroidX) ** 2 * weight;
225	      varianceY += (y - centroidY) ** 2 * weight;
226	    }
227	  }
228	
229	  const spreadX = Math.sqrt(varianceX / totalWeight);
230	  const spreadY = Math.sqrt(varianceY / totalWeight);
231	  const boxWidth = clamp(spreadX * 5.2, width * 0.22, width * 0.92);
232	  const boxHeight = clamp(spreadY * 6.2, height * 0.25, height * 0.94);
233	  const left = clamp(centroidX - boxWidth / 2, 0, width - boxWidth);
234	  const top = clamp(centroidY - boxHeight / 2, 0, height - boxHeight);
235	
236	  const faceBox: FaceBox = {
237	    x: Number((left / width).toFixed(4)),
238	    y: Number((top / height).toFixed(4)),
239	    width: Number((boxWidth / width).toFixed(4)),
240	    height: Number((boxHeight / height).toFixed(4))
241	  };
242	
243	  const faceInFrame =
244	    faceBox.width >= 0.22 &&
245	    faceBox.height >= 0.25 &&
246	    faceBox.x >= 0.02 &&
247	    faceBox.y >= 0.02 &&
248	    faceBox.x + faceBox.width <= 0.98 &&
249	    faceBox.y + faceBox.height <= 0.98;
250	
251	  if (!faceInFrame) {
252	    throw new AppError(400, "face_box_invalid", "Face must be fully in frame");
253	  }
254	
255	  const leftEye = deriveWeightedPoint(
256	    grayscale,
257	    {
258	      left,
259	      top,
260	      right: left + boxWidth * 0.48,
261	      bottom: top + boxHeight * 0.42
262	    },
263	    darkThreshold,
264	    "left eye"
265	  );
266	  const rightEye = deriveWeightedPoint(
267	    grayscale,
268	    {
269	      left: left + boxWidth * 0.52,
270	      top,
271	      right: left + boxWidth,
272	      bottom: top + boxHeight * 0.42
273	    },
274	    darkThreshold,
275	    "right eye"
276	  );
277	  const nose = deriveWeightedPoint(
278	    grayscale,
279	    {
280	      left: left + boxWidth * 0.28,
281	      top: top + boxHeight * 0.32,
282	      right: left + boxWidth * 0.72,
283	      bottom: top + boxHeight * 0.82
284	    },
285	    darkThreshold,
286	    "nose"
287	  );
288	
289	  const landmarks: Landmarks = {
290	    leftEye: normalizePoint(leftEye.x, leftEye.y, width, height),
291	    rightEye: normalizePoint(rightEye.x, rightEye.y, width, height),
292	    nose: normalizePoint(nose.x, nose.y, width, height)
293	  };
294	
295	  if (landmarks.leftEye.x >= landmarks.rightEye.x) {
296	    throw new AppError(400, "face_landmarks_invalid", "Trusted landmark detection did not produce a valid face geometry");
297	  }
298	
299	  return {
300	    faceBox,
301	    landmarks,
302	    faceInFrame
303	  };
304	};
305	
306	const computeTrustedLivenessScore = (
307	  centerLandmarks: Landmarks,
308	  turnLandmarks: Landmarks,
309	  centerFaceBox: FaceBox,
310	  turnFaceBox: FaceBox
311	) => {
312	  const centerMidEye = (centerLandmarks.leftEye.x + centerLandmarks.rightEye.x) / 2;
313	  const turnMidEye = (turnLandmarks.leftEye.x + turnLandmarks.rightEye.x) / 2;
314	  const centerEyeDistance = Math.abs(centerLandmarks.rightEye.x - centerLandmarks.leftEye.x);
315	  const turnEyeDistance = Math.abs(turnLandmarks.rightEye.x - turnLandmarks.leftEye.x);
316	  const noseShift = Math.abs((turnLandmarks.nose.x - turnMidEye) - (centerLandmarks.nose.x - centerMidEye));
317	  const boxShift = Math.abs(
318	    turnFaceBox.x + turnFaceBox.width / 2 - (centerFaceBox.x + centerFaceBox.width / 2)
319	  );
320	  const verticalStabilityPenalty = Math.min(1, Math.abs(centerLandmarks.nose.y - turnLandmarks.nose.y) * 5);
321	  const eyeDistancePenalty = Math.min(1, Math.abs(centerEyeDistance - turnEyeDistance) * 4);
322	  const movementScore = noseShift * 4 + boxShift * 2;
323	  const structuralScore = Math.max(0, 1 - verticalStabilityPenalty - eyeDistancePenalty);
324	
325	  return Math.max(0, Math.min(1, movementScore * 0.85 + structuralScore * 0.15));
326	};
